# Generated by google (gemini-2.5-flash)
# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, ConnectionError, TransportError
import os

app = Flask(__name__)

# --- Configuration ---
# You would typically load these from environment variables or a config file
ELASTICSEARCH_HOST = os.environ.get('ELASTICSEARCH_HOST', 'localhost')
ELASTICSEARCH_PORT = int(os.environ.get('ELASTICSEARCH_PORT', 9200))
ELASTICSEARCH_INDEX = os.environ.get('ELASTICSEARCH_INDEX', 'products')
ELASTICSEARCH_TIMEOUT = int(os.environ.get('ELASTICSEARCH_TIMEOUT', 10)) # seconds

# --- Elasticsearch Client Initialization ---
# It's good practice to initialize the client globally or at app startup
# and reuse it across requests.
es_client = None
try:
    es_client = Elasticsearch(
        [f'http://{ELASTICSEARCH_HOST}:{ELASTICSEARCH_PORT}'],
        timeout=ELASTICSEARCH_TIMEOUT,
        sniff_on_start=True, # Attempt to discover other nodes in the cluster
        sniff_interval=60,   # Sniff every 60 seconds to update node list
        max_retries=3,       # Retry failed requests
        retry_on_timeout=True # Retry if a request times out
    )
    # Ping to check connection immediately
    if not es_client.ping():
        raise ConnectionError("Could not connect to Elasticsearch!")
    print(f"Successfully connected to Elasticsearch at {ELASTICSEARCH_HOST}:{ELASTICSEARCH_PORT}")
except ConnectionError as e:
    print(f"ERROR: Could not connect to Elasticsearch. Please check your ELASTICSEARCH_HOST and ELASTICSEARCH_PORT settings. Error: {e}")
    es_client = None # Ensure client is None if connection fails
except Exception as e:
    print(f"An unexpected error occurred during Elasticsearch connection: {e}")
    es_client = None

# --- API Endpoint ---
@app.route('/api/search', methods=['GET'])
def search_products():
    """
    Searches for products in Elasticsearch based on a keyword query.
    GET /api/search?q=keyword
    """
    if es_client is None:
        return jsonify({"error": "Service unavailable: Could not connect to Elasticsearch."}), 503

    query_keyword = request.args.get('q', '').strip()

    if not query_keyword:
        return jsonify({"message": "Please provide a 'q' parameter for your search query."}), 400

    try:
        # Define the Elasticsearch search query
        # Using multi_match for searching across multiple fields
        # 'best_fields' type finds documents that match any field, but scores
        # based on the best-matching field.
        search_body = {
            "query": {
                "multi_match": {
                    "query": query_keyword,
                    "fields": ["name^3", "description^1", "category^2", "tags^1"], # Boost important fields
                    "type": "best_fields"
                }
            },
            "size": 10,  # Limit results to 10 for a typical search page
            "sort": [
                "_score", # Sort by relevance
                {"name.keyword": {"order": "asc"}} # Secondary sort for consistent ordering
            ]
        }

        # Execute the search query
        response = es_client.search(
            index=ELASTICSEARCH_INDEX,
            body=search_body
        )

        hits = response['hits']['hits']
        products = []
        for hit in hits:
            product = hit['_source']
            product['id'] = hit['_id'] # Add the document ID
            products.append(product)

        return jsonify({
            "query": query_keyword,
            "total_results": response['hits']['total']['value'],
            "products": products
        }), 200

    except ConnectionError:
        return jsonify({"error": "Failed to connect to Elasticsearch. Please try again later."}), 503
    except TransportError as e:
        # Catch specific Elasticsearch transport errors (e.g., index not found)
        if e.status_code == 404 and "index_not_found_exception" in str(e):
            return jsonify({"error": f"Search index '{ELASTICSEARCH_INDEX}' not found. Please ensure it exists."}), 404
        print(f"Elasticsearch Transport Error: {e}")
        return jsonify({"error": f"An Elasticsearch error occurred: {e.error}"}), 500
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return jsonify({"error": "An unexpected server error occurred."}), 500

# --- Health Check (Optional but Recommended) ---
@app.route('/api/health', methods=['GET'])
def health_check():
    if es_client and es_client.ping():
        return jsonify({"status": "healthy", "elasticsearch_status": "connected"}), 200
    else:
        return jsonify({"status": "unhealthy", "elasticsearch_status": "disconnected"}), 500

# --- Main execution block ---
if __name__ == '__main__':
    # For production, use a production-ready WSGI server like Gunicorn or uWSGI
    # For development:
    app.run(host='0.0.0.0', port=5000, debug=True)